const AWS = require('aws-sdk');
const s3 = new AWS.S3();

exports.handler = async (event) => {
  const bucketName = event.Records[0].s3.bucket.name;
  const objectKey = decodeURIComponent(event.Records[0].s3.object.key.replace(/\+/g, ' '));
  const originalFilename = objectKey.split('/').pop();

  // Validate untrusted input and use secure platform APIs
  if (!originalFilename.match(/^[\w-]+\.[^\.]+$/)) {
    throw new Error('Invalid filename');
  }

  // Apply least privilege and explicit allowlists where relevant
  const s3Object = await s3.getObject({ Bucket: bucketName, Key: objectKey }).promise();
  if (!s3Object.Body) {
    throw new Error('File not found');
  }

  // Keep secrets, tokens, and sensitive data out of plaintext storage and logs
  const processedData = processFile(s3Object.Body);
  const outputKey = `processed/${originalFilename}`;
  await s3.putObject({ Bucket: bucketName, Key: outputKey, Body: processedData }).promise();
};

